<!-- Card.vue -->
<template>
  <router-link class="card-link" :to="{ name: 'box', params: { slug: box.slug } }">
    <div class="card">
      <!-- Основная обёртка с изображением -->
      <div class="card-wrapper">
        <img :src="coverSrc" class="cover-image" :alt="box.name" />
        
        <!-- Градиент для читаемости текста -->
        <div class="card-gradient"></div>
        
        <!-- Быстрые действия (показываются при наведении) -->
        <div class="quick-actions">
          <button 
            class="action-btn favorite-btn"
            @click.prevent="toggleFavorite"
            :title="isFavorite ? 'Убрать из избранного' : 'В избранное'"
          >
            <svg 
              width="20" 
              height="20" 
              viewBox="0 0 24 24" 
              :fill="isFavorite ? '#35C66B' : 'none'" 
              :stroke="isFavorite ? '#35C66B' : '#fff'" 
              stroke-width="2"
              stroke-linecap="round" 
              stroke-linejoin="round"
            >
              <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
            </svg>
          </button>
          <button 
            class="action-btn cart-btn"
            @click.prevent="addToCart"
            title="В корзину"
            :disabled="isAddingToCart"
          >
            <svg 
              v-if="!isAddingToCart"
              width="20" 
              height="20" 
              viewBox="0 0 24 24" 
              fill="none" 
              stroke="#fff" 
              stroke-width="2"
              stroke-linecap="round" 
              stroke-linejoin="round"
            >
              <circle cx="9" cy="21" r="1"/>
              <circle cx="20" cy="21" r="1"/>
              <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/>
            </svg>
            <span v-else class="cart-checkmark">✓</span>
          </button>
        </div>
      </div>

      <!-- Название как картинка (для особого стиля) -->
      <!-- <img v-if="box.titleImage" :src="box.titleImage" class="title" :alt="box.name" />
      <div v-else class="title-text white-text montserrat-bold">{{ box.name }}</div> -->
      <!-- Персонаж/декор (появляется при наведении) -->
      <!-- <img v-if="box.characterImage" :src="box.characterImage" class="character" alt="" /> -->

      <!-- Информационный блок (всегда виден) -->
      <div class="card-info">
        <div class="card-title white-text montserrat-bold">{{ box.name }}</div>
        <div class="info-top">
          <span class="emotion-tag montserrat-medium">{{ box.emotion }}</span>
          <span class="price montserrat-bold">{{ formatPrice(boxPrice) }} ₽</span>
        </div>
        <div class="composition">
          <template v-for="(item, index) in shortComposition" :key="index">
            <span class="composition-item montserrat-regular">{{ item }}</span>
            <span v-if="index < shortComposition.length - 1" class="dot">•</span>
          </template>
        </div>
      </div>
    </div>
  </router-link>
</template>

<script setup>
import { ref, computed, onMounted } from 'vue'
// Если в проекте есть эти утилиты — раскомментируйте
import { calculateBoxPrice, getShortComposition } from '@/data/boxes'
import { cartUtils } from '@/utils/cartUtils'
import { favoritesUtils } from '@/utils/favoritesUtils'

const props = defineProps({
  box: {
    type: Object,
    required: true
  }
})

const isFavorite = ref(false)
const isAddingToCart = ref(false)

// Визуальные источники изображений — поддерживаем оба варианта ключей (image / coverImage)
const coverSrc = computed(() => {
  return props.box.coverImage || props.box.image || ''
})

// Ссылка: если есть slug — используем, иначе '#'
const linkHref = computed(() => {
  return props.box.slug ? `/box/${props.box.slug}` : '#'
})

// Цена бокса — используем внешний calculateBoxPrice если есть, иначе fallback на box.price
const boxPrice = computed(() => {
  try {
    // если функция присутствует и возвращает валидное значение — используем её
    const p = calculateBoxPrice ? calculateBoxPrice(props.box.id) : undefined
    return (typeof p === 'number' && !isNaN(p)) ? p : (props.box.price ?? 0)
  } catch (e) {
    return props.box.price ?? 0
  }
})

// Короткий состав для отображения — используем внешний getShortComposition если есть, иначе берем box.shortComposition
const shortComposition = computed(() => {
  try {
    const arr = getShortComposition ? getShortComposition(props.box.id) : undefined
    if (Array.isArray(arr) && arr.length) return arr
  } catch (e) {
    // ignore
  }
  if (Array.isArray(props.box.shortComposition) && props.box.shortComposition.length) {
    return props.box.shortComposition
  }
  // В крайнем случае попробуем собрать из box.composition (если это строка/массив)
  if (Array.isArray(props.box.composition)) return props.box.composition.slice(0, 3)
  if (typeof props.box.composition === 'string') {
    return props.box.composition.split(',').map(s => s.trim()).filter(Boolean).slice(0, 3)
  }
  return []
})

// Переключить избранное
const toggleFavorite = () => {
  // Если есть утилита favoritesUtils — используем её:
  const added = favoritesUtils.toggle(props.box.id)
  isFavorite.value = added

  // Иначе — простая локальная логика (переключение)
  // const added = !isFavorite.value
  // isFavorite.value = added

  console.log(added ? 'Добавлено в избранное' : 'Удалено из избранного', props.box.name)
}

// Добавить в корзину
const addToCart = () => {
  if (isAddingToCart.value) return

  isAddingToCart.value = true

  // Если есть cartUtils — можно вызвать cartUtils.addBox(props.box.id)
  cartUtils.addBox(props.box.id)
  console.log('Добавлено в корзину:', props.box.name)

  // Визуальная индикация успеха
  setTimeout(() => {
    isAddingToCart.value = false
  }, 1500)
}

// Перейти на страницу бокса
const navigateToBox = () => {
  // Сначала пробуем перейти через slug, если есть
  if (props.box.slug) {
    // Попытка использовать history API (роутер) — если у вас есть Vue Router, замените на router.push
    try {
      window.location.href = `/box/${props.box.slug}`
    } catch (e) {
      console.log('Navigate to:', `/box/${props.box.slug}`)
    }
  } else {
    // Нет страницы — можно открыть ссылку по href (в нашем случае '#')
    console.log('No slug for box:', props.box.name)
  }
}

// Форматировать цену
const formatPrice = (price) => {
  const p = Number(price) || 0
  return p.toLocaleString('ru-RU')
}

// Проверить избранное при монтировании (если есть утилиты)
onMounted(() => {
  if (favoritesUtils && favoritesUtils.isFavorite) {
    isFavorite.value = favoritesUtils.isFavorite(props.box.id)
  } else if (props.box.isFavorite) {
    isFavorite.value = !!props.box.isFavorite
  }
  if (props.box.isFavorite) {
    isFavorite.value = !!props.box.isFavorite
  }
})
</script>


