// Добавляем ещё боксов для демонстрации пагинации (дублируем с другими ID)
for (let i = 0; i < 12; i++) {
  const originalBox = boxes[i % boxes.length]
  boxes.push({
    ...originalBox,
    id: `${originalBox.id}-copy-${i}`,
    name: `${originalBox.name} #${i + 2}`
  })
}

// Функция расчёта цены
export function calculateBoxPrice(boxId, customComposition = null) {
  const box = boxes.find(b => b.id === boxId)
  if (!box) return 0
  
  const composition = customComposition || box.defaultComposition
  return composition.reduce((sum, item) => {
    const product = products[item.productId]
    return sum + (product.price * item.quantity)
  }, 0)
}

// Функция получения короткого состава для карточки
export function getShortComposition(boxId) {
  const box = boxes.find(b => b.id === boxId)
  if (!box) return []
  
  return box.defaultComposition
    .slice(0, 3)
    .map(item => products[item.productId].name)
}

// ============= /utils/cartUtils.js =============
const CART_KEY = 'box_cart'

export const cartUtils = {
  // Получить корзину
  getCart() {
    try {
      const cart = localStorage.getItem(CART_KEY)
      return cart ? JSON.parse(cart) : { items: [] }
    } catch (e) {
      console.error('Error reading cart:', e)
      return { items: [] }
    }
  },

  // Сохранить корзину
  saveCart(cart) {
    try {
      localStorage.setItem(CART_KEY, JSON.stringify(cart))
    } catch (e) {
      console.error('Error saving cart:', e)
    }
  },

  // Добавить бокс в корзину (дефолтный состав)
  addBox(boxId) {
    const cart = this.getCart()
    const cartItem = {
      id: `cart-${Date.now()}-${Math.random()}`,
      boxId,
      customComposition: null,
      totalPrice: calculateBoxPrice(boxId),
      addedAt: Date.now()
    }
    cart.items.push(cartItem)
    this.saveCart(cart)
    return cartItem
  },

  // Обновить состав бокса в корзине
  updateBoxComposition(cartItemId, customComposition) {
    const cart = this.getCart()
    const item = cart.items.find(i => i.id === cartItemId)
    if (item) {
      item.customComposition = customComposition
      item.totalPrice = customComposition.reduce((sum, comp) => {
        const product = products[comp.productId]
        return sum + (product.price * comp.quantity)
      }, 0)
      this.saveCart(cart)
    }
  },

  // Удалить из корзины
  removeItem(cartItemId) {
    const cart = this.getCart()
    cart.items = cart.items.filter(i => i.id !== cartItemId)
    this.saveCart(cart)
  },

  // Очистить корзину
  clear() {
    this.saveCart({ items: [] })
  }
}

// ============= /utils/favoritesUtils.js =============
const FAVORITES_KEY = 'box_favorites'

export const favoritesUtils = {
  // Получить избранное
  getFavorites() {
    try {
      const favs = localStorage.getItem(FAVORITES_KEY)
      return favs ? JSON.parse(favs) : { boxIds: [] }
    } catch (e) {
      console.error('Error reading favorites:', e)
      return { boxIds: [] }
    }
  },

  // Сохранить избранное
  saveFavorites(favorites) {
    try {
      localStorage.setItem(FAVORITES_KEY, JSON.stringify(favorites))
    } catch (e) {
      console.error('Error saving favorites:', e)
    }
  },

  // Проверить в избранном ли
  isFavorite(boxId) {
    const favs = this.getFavorites()
    return favs.boxIds.includes(boxId)
  },

  // Переключить избранное
  toggle(boxId) {
    const favs = this.getFavorites()
    const index = favs.boxIds.indexOf(boxId)
    
    if (index > -1) {
      favs.boxIds.splice(index, 1)
    } else {
      favs.boxIds.push(boxId)
    }
    
    this.saveFavorites(favs)
    return index === -1 // вернуть true если добавили
  }
}