const FAVORITES_KEY = 'box_favorites'

export const favoritesUtils = {
  // Получить избранное из localStorage
  getFavorites() {
    try {
      const favs = localStorage.getItem(FAVORITES_KEY)
      return favs ? JSON.parse(favs) : { boxIds: [] }
    } catch (e) {
      console.error('Error reading favorites:', e)
      return { boxIds: [] }
    }
  },

  // Сохранить избранное в localStorage
  saveFavorites(favorites) {
    try {
      localStorage.setItem(FAVORITES_KEY, JSON.stringify(favorites))
    } catch (e) {
      console.error('Error saving favorites:', e)
    }
  },

  // Проверить, находится ли бокс в избранном
  isFavorite(boxId) {
    const favs = this.getFavorites()
    return favs.boxIds.includes(boxId)
  },

  // Переключить избранное (добавить или удалить)
  toggle(boxId) {
    const favs = this.getFavorites()
    const index = favs.boxIds.indexOf(boxId)
    
    if (index > -1) {
      // Удалить из избранного
      favs.boxIds.splice(index, 1)
    } else {
      // Добавить в избранное
      favs.boxIds.push(boxId)
    }
    
    this.saveFavorites(favs)
    return index === -1 // вернуть true если добавили, false если удалили
  },

  // Добавить в избранное
  add(boxId) {
    const favs = this.getFavorites()
    if (!favs.boxIds.includes(boxId)) {
      favs.boxIds.push(boxId)
      this.saveFavorites(favs)
      return true
    }
    return false
  },

  // Удалить из избранного
  remove(boxId) {
    const favs = this.getFavorites()
    favs.boxIds = favs.boxIds.filter(id => id !== boxId)
    this.saveFavorites(favs)
  },

  // Очистить всё избранное
  clear() {
    this.saveFavorites({ boxIds: [] })
  },

  // Получить количество элементов в избранном
  getCount() {
    const favs = this.getFavorites()
    return favs.boxIds.length
  }
}

